/**
 * @name XSS in admin beans HTML output generation
 * @description Admin bean getDoForm/getForm methods returning HTML with unencoded user data
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-admin-html-form
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module AdminFormXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Returned from methods that produce HTML, which gets written to response
    exists(ReturnStmt ret |
      ret.getResult() = sink.asExpr() and
      ret.getEnclosingCallable().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.wiki.ui.admin", "AdminBean")
    )
    or
    // String builder/buffer being appended to in admin bean methods
    exists(MethodCall mc |
      (mc.getMethod().hasName("append") or mc.getMethod().hasName("toString")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "StringBuilder") and
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ui.admin%") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module AdminFormXssFlow = TaintTracking::Global<AdminFormXssConfig>;
import AdminFormXssFlow::PathGraph

from AdminFormXssFlow::PathNode source, AdminFormXssFlow::PathNode sink
where AdminFormXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in admin bean HTML: user-controlled data from $@ flows to HTML output without encoding.", source.getNode(), "user input"

/**
 * @name XSS in SearchManagerBean and UserBean admin forms
 * @description Admin beans building HTML with search queries or user input unencoded
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-searchmanager-userbean
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SearchUserBeanConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // StringBuilder appends in SearchManagerBean or UserBean
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "StringBuilder") and
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ui.admin.beans.%") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Returned HTML string from getDoForm/doPost in admin beans
    exists(ReturnStmt ret |
      ret.getResult() = sink.asExpr() and
      ret.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ui.admin.beans.%")
    )
  }
}

module SearchUserBeanFlow = TaintTracking::Global<SearchUserBeanConfig>;
import SearchUserBeanFlow::PathGraph

from SearchUserBeanFlow::PathNode source, SearchUserBeanFlow::PathNode sink
where SearchUserBeanFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in admin bean: user-controlled data from $@ reaches HTML output without encoding.", source.getNode(), "user input"
